        "R1 running-config (GigabitEthernet0/0/1): Cisco-IOS-XE-ethernet:negotiation.auto = true",
        "R2 running-config (GigabitEthernet0/0/1): Cisco-IOS-XE-ethernet:speed = value-100; Cisco-IOS-XE-ethernet:duplex = half; Cisco-IOS-XE-ethernet:negotiation.auto = false",
        "R1 interface status GigabitEthernet0/0/1: admin_state = up, oper_state = up, duplex = null, input_errors = 81, output_errors = 0"
      ],
      "confidence": 0.9
    }
  ],
  "missing_info": []
}

